#!/usr/bin/env node

const fs = require('fs');
const prefix = '@universal-robots';
const semVerRegExp = new RegExp(/\d+\.\d+\.\d+/);

const args = process.argv.slice(2);
if (args.length != 2) {
    console.error(`Error: 2 parameters needed: package.json file, destination file `);
    process.exitCode = 1;
}
const sourceFile = args[0];
const destFile = args[1];
const packageJson = JSON.parse(fs.readFileSync(sourceFile, 'utf8'))
fs.appendFileSync(destFile, "#This is a generated file. Editing this file will not affect the build\n");

appendToFile(getFormattedURDependencies(packageJson.dependencies));
appendToFile(getFormattedURDependencies(packageJson.devDependencies));

function appendToFile(dependencies) {
    for (dependency of dependencies) {
        fs.appendFileSync(destFile, dependency+'\n');
    }
}

function getFormattedURDependencies(rawDependencies) {
    let formattedDependencies = [];
    let dependencyName;
    for (dependencyName in rawDependencies) {
        if (rawDependencies.hasOwnProperty(dependencyName) && dependencyName.includes(prefix)) {
            const formattedDependency = format(dependencyName,rawDependencies[dependencyName]);
            formattedDependencies.push(formattedDependency);
        }
    }
    return formattedDependencies;
}

function format(dependencyName,dependencyVersion) {
    return dependencyName + ':'+dependencyVersion.match(semVerRegExp);
}
